def generate_self_signed_cert(key_file, cert_file, cn="Internal IdP", days=365):
    """Generate a self-signed certificate for signing or SSL."""
    key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=2048,
        backend=default_backend(),
    )

    subject = issuer = x509.Name([
        x509.NameAttribute(NameOID.COUNTRY_NAME, "US"),
        x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, "Internal"),
        x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Internal Organization"),
        x509.NameAttribute(NameOID.COMMON_NAME, cn),
    ])

    cert = (
        x509.CertificateBuilder()
        .subject_name(subject)
        .issuer_name(issuer)
        .public_key(key.public_key())
        .serial_number(x509.random_serial_number())
        .not_valid_before(datetime.datetime.utcnow())
        .not_valid_after(datetime.datetime.utcnow() + datetime.timedelta(days=days))
        .add_extension(
            x509.SubjectAlternativeName([
                x509.DNSName("idp.internal.example.com"),
                x509.DNSName("localhost"),
            ]),
            critical=False,
        )
        .sign(key, hashes.SHA256(), default_backend())
    )

    with open(key_file, "wb") as f:
        f.write(key.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.TraditionalOpenSSL,
            encryption_algorithm=serialization.NoEncryption(),
        ))

    with open(cert_file, "wb") as f:
        f.write(cert.public_bytes(serialization.Encoding.PEM))

    return key, cert


def ensure_certificates():
    """Ensure all required certificates exist."""
    os.makedirs(CERT_DIR, exist_ok=True)

    if not os.path.exists(IDP_KEY_FILE) or not os.path.exists(IDP_CERT_FILE):
        print("Generating IdP signing certificate...")
        generate_self_signed_cert(IDP_KEY_FILE, IDP_CERT_FILE, cn="Internal IdP Signing")

    if not os.path.exists(SSL_KEY_FILE) or not os.path.exists(SSL_CERT_FILE):
        print("Generating SSL certificate...")
        generate_self_signed_cert(SSL_KEY_FILE, SSL_CERT_FILE, cn="idp.internal.example.com")


def load_idp_credentials():
    """Load IdP signing key and certificate."""
    with open(IDP_KEY_FILE, "rb") as f:
        key = f.read()
    with open(IDP_CERT_FILE, "rb") as f:
        cert = f.read()
    return key, cert


def get_cert_pem_body(cert_pem):
    """Extract the base64 body from a PEM certificate (strip headers)."""
    lines = cert_pem.decode("utf-8").strip().split("\n")
    body_lines = [l for l in lines if not l.startswith("-----")]
    return "".join(body_lines)


