def parse_saml_request(saml_request_encoded):
    """Parse and decode a SAML AuthnRequest."""
    try:
        decoded = base64.b64decode(saml_request_encoded)
        try:
            xml_string = zlib.decompress(decoded, -15)
        except zlib.error:
            xml_string = decoded

        root = etree.fromstring(xml_string)
        request_data = {
            "id": root.get("ID"),
            "issuer": None,
            "acs_url": root.get("AssertionConsumerServiceURL"),
            "destination": root.get("Destination"),
            "protocol_binding": root.get("ProtocolBinding"),
        }

        issuer_elem = root.find("{%s}Issuer" % SAML_NS)
        if issuer_elem is not None:
            request_data["issuer"] = issuer_elem.text

        return request_data
    except Exception as e:
        print(f"Error parsing SAML request: {e}")
        return None


